-- ── Cloud-IAM ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Cloud-IAM is a managed hosting service for Keycloak, the open-source identity and access management server, providing dedicated instances, automated operations, and expert support so teams do not have to self-host and maintain Keycloak. The service has operated since 2018 and is delivered by a joint venture of ELLIXO SAS and FGRibreau SARL, headquartered in Rennes, France. It offers deployment across more than 70 regions on providers including AWS, Google Cloud, Azure, Scaleway, and Outscale.$q$, short_description),
  pricing_model = COALESCE($q$Tiered subscription priced by total number of user accounts (not monthly active users), with a free tier and usage-based paid plans$q$, pricing_model),
  starting_price = COALESCE($q$Free tier available for up to 100 users; paid plans start around 225 euros/month$q$, starting_price),
  founded_year = COALESCE(2018, founded_year),
  company_size = COALESCE($q$11 employees$q$, company_size),
  headquarters = COALESCE($q$Rennes, France$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$French$q$]::text[],
  seo_title = COALESCE($q$Cloud-IAM Review: Managed Keycloak Pricing and Features$q$, seo_title),
  seo_meta_description = COALESCE($q$Cloud-IAM review: pricing, uptime SLAs, and features of this managed Keycloak identity and access management hosting service based in France.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Cloud-IAM is a managed hosting service for Keycloak, the widely used open-source identity and access management (IAM) server, designed for teams that want Keycloak's single sign-on, OAuth2, and OpenID Connect capabilities without operating the underlying infrastructure themselves. The service has been running since 2018 under the tagline Keycloak Experts Since 2018, and it is delivered by a joint venture of two French technology companies, ELLIXO SAS and FGRibreau SARL, headquartered in Rennes, in the Brittany region of France. The company is small, reported at around 11 employees, but it draws on a broader engineering bench through ELLIXO, which has more than 30 engineers specialized in hosting and tuning Java-based software, giving Cloud-IAM deep operational expertise in the Java-based Keycloak stack specifically. Cloud-IAM provisions a fully dedicated Keycloak deployment per customer, rather than a shared multi-tenant instance, in the cloud region of the customer's choice, drawing on more than 70 available regions across major providers including AWS, Google Cloud, Microsoft Azure, and European providers Scaleway and Outscale. This gives European customers, in particular, a way to keep identity data within the EU for GDPR compliance while still using major-cloud-grade infrastructure. Deployments are typically live within about 20 minutes of setup, and the service includes automated backups, built-in redundancy, and a 99.95 percent uptime SLA on its most popular tier, backed by 24/7 expert support from engineers focused specifically on Keycloak rather than generalist cloud support staff. Pricing is structured around the total number of user accounts provisioned in Keycloak rather than monthly active users, which the company positions as more predictable for budgeting since it does not spike with login activity. The plan structure includes a Freemium tier for up to 100 users with community support and roughly 99 percent uptime, a Starter tier and an Essential tier both beginning around 225 euros per month with community or email and ticket support respectively, a Premium tier also from around 225 euros per month that adds 24/7 on-call support and a day of included monthly consulting, and a custom-priced Max tier for the largest deployments requiring multi-region redundancy and a 30-minute incident-response commitment. All paid tiers include enterprise security certifications such as ISO 27001:2022 and SOC 2 Type 2, along with GDPR compliance documentation, which is a common purchasing requirement for the regulated industries, such as banking, healthcare, and public sector, that frequently adopt Keycloak. Cloud-IAM's core competitive position is that it removes the operational burden of self-hosting and patching Keycloak, including version upgrades, extension development, and custom domain and SSL configuration, all of which can be handled through the Cloud-IAM console without additional engineering fees on most plans. It competes with other Keycloak-hosting providers and with the alternative of self-managing Keycloak on raw cloud infrastructure or adopting a proprietary IAM product such as Auth0, Okta, or AWS Cognito instead of the open-source Keycloak project.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '0fcbe957-d0e4-46b4-87eb-14e727ae4ab2';

