-- ── Cloud4Wi ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Cloud4Wi is a cloud-native, AI-powered WiFi platform that turns guest and resident WiFi networks into a customer engagement and analytics layer for physical venues such as retail stores, hospitality brands, and transit locations. The platform unifies Guest WiFi, MDU (multi-dwelling unit) WiFi, and Cloud Network Access Control on a single, hardware-independent architecture, powered by an AI engine called Hedy. Founded in February 2014 by Andrea Calcagno and Davide Quadrini, the company is now headquartered in Brooklyn, New York, after starting in Pisa, Italy.$q$, short_description),
  pricing_model = COALESCE($q$Usage-based subscription priced per access point, per personal network, or per user depending on product, billed monthly or annually, with a self-serve free trial and custom Enterprise pricing for larger deployments$q$, pricing_model),
  starting_price = COALESCE($q$From $200/month per product (billed annually from $2,400/year), 30-day free trial available$q$, starting_price),
  founded_year = COALESCE(2014, founded_year),
  company_size = COALESCE($q$51-200 employees$q$, company_size),
  headquarters = COALESCE($q$Brooklyn, New York, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$Italian$q$]::text[],
  seo_title = COALESCE($q$Cloud4Wi Review: Pricing, Features, and Guest WiFi$q$, seo_title),
  seo_meta_description = COALESCE($q$Cloud4Wi review: pricing, Hedy AI Engine, Guest WiFi and MDU WiFi features for retail, hospitality, and transit customer engagement platforms.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Cloud4Wi is a cloud-native WiFi and customer-engagement platform used by physical venues, including retailers, hospitality brands, cruise lines, shopping centers, and transit operators, to turn guest WiFi networks into a source of first-party customer data and real-time engagement rather than simple internet connectivity. The company was founded in February 2014 by Andrea Calcagno and Davide Quadrini, originally headquartered in Pisa, Italy, before relocating its corporate offices to San Francisco following a Series A round led by United Ventures, and later moving its corporate headquarters to New York in 2019; the company is now based in Brooklyn, New York. Cloud4Wi has raised roughly 18 million dollars in funding, including a Series B round of about 11.5 million dollars in 2017 co-led by Opus Capital and United Ventures. The platform unifies three products on one hardware-independent architecture: Guest WiFi, which delivers branded captive-portal onboarding and consent-based data capture for visitors; MDU WiFi, aimed at multi-dwelling residential properties; and Cloud Network Access Control (Cloud NAC), which extends the same architecture to secure network access use cases. All three products are powered by an AI engine called Hedy, which proactively detects network issues before they affect guests, proposes resolutions, and lets administrators ask plain-language questions to get live analytics on connections, venues, and contacts, along with ready-to-use reports and guided actions. Cloud4Wi is deliberately hardware-independent, integrating with existing access point and controller infrastructure from vendors including Cisco, Meraki, Aruba, Mist, Ubiquiti, Ruckus, and Extreme via standard protocols such as RADIUS, RadSec, 802.1X, Passpoint, and OpenRoaming, so customers can layer Cloud4Wi onto their current network estate without replacing hardware or facing firmware lock-in. The platform is SOC 2 Type II certified and is used at scale by well-known brands including Prada, MSC Cruises, Guess, and the shopping center operator Carmila; the company reports its platform is trusted across more than 70,000 locations serving over 300 million users worldwide. A publicized case with Guess describes the retailer scaling Cloud4Wi from roughly 90 European stores to more than 700 global locations, using branded WiFi onboarding to capture consent-based customer data feeding an AI-powered marketing stack, generating more than 35,000 new customer profiles per month and capturing over one million real-time interaction events annually. Pricing is public and usage-based rather than requiring a sales call for baseline tiers: each product starts around 200 dollars per month (roughly 2,400 dollars per year when billed annually), scaling by the number of access points included for Guest WiFi, personal networks for MDU WiFi, or users for Cloud NAC, with every tier including the full feature set, meaning there are no separate paid add-ons for the captive portal, the Hedy AI Engine, Passpoint and OpenRoaming support, the MyData customer portal, or CRM integrations. A 30-day free trial requiring no credit card is available for self-serve evaluation, while larger deployments above roughly 250 access points or 1,000 users move to custom Enterprise pricing negotiated with the Cloud4Wi sales team.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'f1dbcfa2-6b82-4d0b-bc9c-353914d887fa';

