-- ── CloudAMQP ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$CloudAMQP is a managed hosting service for RabbitMQ and LavinMQ message brokers, handling setup, monitoring, clustering, and backups so teams can add message queuing to their applications without operating broker infrastructure themselves. It is operated by 84codes AB, a Swedish company founded in 2012 by Carl Horberg and headquartered in Gothenburg, Sweden. The service is available on AWS, Google Cloud, and Azure across 19 cloud regions worldwide.$q$, short_description),
  pricing_model = COALESCE($q$Tiered subscription with free multi-tenant plans, paid multi-tenant plans, and dedicated per-node plans billed per second based on availability; add-ons for VPC and extra disk space$q$, pricing_model),
  starting_price = COALESCE($q$Free tier available; paid dedicated plans start around $49/month$q$, starting_price),
  founded_year = COALESCE(2012, founded_year),
  company_size = COALESCE($q$Not publicly disclosed (small team)$q$, company_size),
  headquarters = COALESCE($q$Gothenburg, Sweden$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$CloudAMQP Review: Managed RabbitMQ Pricing and Features$q$, seo_title),
  seo_meta_description = COALESCE($q$CloudAMQP review: pricing, plans, and features of this managed RabbitMQ and LavinMQ hosting service from 84codes, available on AWS, GCP, and Azure.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$CloudAMQP is a managed message-broker hosting service that lets development teams run RabbitMQ and LavinMQ, two open-source AMQP-compatible message queuing systems, without provisioning or operating the underlying broker infrastructure themselves. It is the flagship product of 84codes AB, a Swedish technology company founded in 2012 by Carl Horberg and headquartered in Gothenburg, Sweden, which has been recognized as one of Europe's long-term growth companies by the Financial Times. Alongside CloudAMQP, 84codes also operates CloudMQTT, a managed MQTT broker service, and develops LavinMQ itself, an in-house-built, high-performance AMQP 1.0 message broker written in the Crystal programming language and designed as a resource-efficient, high-throughput alternative to RabbitMQ. CloudAMQP automates the entire lifecycle of a message broker deployment, including setup, TLS encryption, monitoring, clustering, and automatic backups, and it is available across all major cloud platforms, spanning AWS, Google Cloud Platform, and Microsoft Azure, in 19 cloud regions globally, which lets customers co-locate their message broker in the same region and even the same virtual private cloud as their application infrastructure. Pricing is structured in two broad categories. Multi-tenant, shared-server plans are the most economical option and include a genuinely free tier for both RabbitMQ (called Little Lemur, offering 1 million messages per month, 20 connections, and 100 queues) and LavinMQ (called Loyal Lemming, offering 2 million messages per month, 40 connections, and 200 queues), plus paid shared plans (Tough Tiger for RabbitMQ and Elegant Ermine for LavinMQ) priced around 19 dollars per month with higher throughput limits. Dedicated, single-tenant plans provide guaranteed resources on their own virtual machines and range from entry-level options, such as the roughly 49 to 50 dollar per month single-node RabbitMQ or LavinMQ plans, up through high-throughput, multi-availability-zone clustered plans costing several thousand to over 17,000 dollars per month for the largest tiers, which support throughput figures ranging from a few hundred messages per second up to hundreds of thousands or over a million messages per second on the top LavinMQ tier. All plans are billed on a per-second basis, meaning the monthly invoice reflects actual instance uptime rather than a flat recurring charge regardless of usage, and optional add-ons include a dedicated Virtual Private Cloud for around 99 dollars per month and additional disk space billed at roughly 0.35 dollars per gigabyte per month. CloudAMQP publishes SOC 2 and SOC 3 compliance reports, and the service is commonly used by backend and DevOps teams to decouple microservices, handle asynchronous task queues, buffer traffic spikes, and implement event-driven architectures without the operational overhead of running RabbitMQ or LavinMQ clusters by hand. The company's exact employee headcount is not publicly disclosed, consistent with 84codes operating as a lean, engineering-focused Swedish company rather than a large, multi-department enterprise vendor.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'da011c25-1ab6-4391-85b0-7e5c3ab1d6ac';

